plane_3_viscosity:
// Viscosity simulation for Plane 3 (0.45)
float viscosity = 0.45;
float drag = 1.0 - (viscosity * 0.1);
vec3 velocity = initialVelocity * drag;

// Liquid shadow pooling
float shadowViscosity = 0.8;
vec2 shadowFlow = gradient * shadowViscosity * deltaTime;

emissive_mix:
// Plane 3: 40% emissive, 60% reflected
vec3 baseColor = texture(diffuse, uv).rgb;
vec3 emissive = texture(emissiveMap, uv).rgb * 0.4;
vec3 reflected = texture(environment, reflectionVec).rgb * 0.6;
vec3 finalColor = baseColor + emissive + reflected;

oil_slick_boundary:
// Plane 3→4 boundary shader
vec2 uv = fragCoord.xy / iResolution.xy;
float time = iTime * 0.2;

// Heat shimmer distortion
vec2 distortion = vec2(
    sin(uv.y * 20.0 + time) * 0.02,
    cos(uv.x * 20.0 + time) * 0.02
);

// Iridescence calculation
float angle = dot(normalize(uv - 0.5), vec2(0.5));
vec3 irid = 0.5 + 0.5 * cos(time + angle * 10.0 + vec3(0, 2, 4));

vec4 color = texture(iChannel0, uv + distortion) * vec4(irid, 1.0);

glimmer_swarm:
// Boid-based swarm visualization
vec3 Boid(vec2 uv, vec2 position, vec2 velocity) {
    vec2 toBoid = uv - position;
    float dist = length(toBoid);
    if (dist > 0.05) return vec3(0);

    float angle = atan(velocity.y, velocity.x);
    float specular = pow(max(dot(normalize(toBoid), normalize(velocity)), 0.0), 32.0);

    return vec3(0.8, 0.9, 1.0) * specular * (1.0 - dist/0.05);
}

ley_line_glow:
// Violet pit glow for eels
float VioletGlow(vec2 uv, vec2 pitCenter) {
    float dist = distance(uv, pitCenter);
    float glow = exp(-dist * 20.0) * 0.8;
    return glow;
}

vec3 leyLineEel = vec3(0.9, 0.9, 1.0) * 0.3; // Translucent body
leyLineEel += vec3(0.58, 0.0, 0.83) * VioletGlow(uv, pitPos); // Violet pits

formation_noise:
// Crystallization pop noise
float PopNoise(vec2 uv, float time) {
    float noise = fract(sin(dot(uv, vec2(12.9898, 78.233))) * 43758.5453);
    float trigger = step(0.997, noise); // Rare events
    float decay = exp(-mod(time, 3.0) * 2.0);
    return trigger * decay;
}

geometric_vine:
// 90-degree constrained growth
float GeometricVine(vec2 uv, vec2 start, int segments) {
    float thickness = 0.005;
    float d = 1.0;

    vec2 current = start;
    for(int i = 0; i < segments; i++) {
        // Random 90-degree turn
        float angle = floor(fract(sin(float(i) * 12.34) * 4.0) * 4.0) * 1.5708;
        vec2 next = current + vec2(cos(angle), sin(angle)) * 0.1;

        // Line segment distance
        float lineDist = length(uv - clamp(uv, min(current, next), max(current, next)));
        d = min(d, lineDist);

        current = next;
    }
    return 1.0 - smoothstep(0.0, thickness, d);
}
